const Gallery = () => (
  <section>
    <h2>Hình ảnh cửa hàng</h2>
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
      <img src="/images/p1.jpg" width="200" alt="Cake 1" />
      <img src="/images/p2.jpg" width="200" alt="Cake 2" />
      <img src="/images/p3.jpg" width="200" alt="Cake 2" />
      <img src="/images/p4.jpg" width="200" alt="Cake 2" />
      {/* Thêm nhiều ảnh khác tại đây */}
    </div>
  </section>
);
export default Gallery;
